from math import gcd
class Solution:
    def countDifferentSubsequenceGCDs(self, nums):
        n = len(nums)
        found = set()
        for mask in range(1, 1 << n):
            g = 0
            for i in range(n):
                if mask & (1 << i):
                    g = gcd(g, nums[i])
            found.add(g)
        return len(found)

