from math import gcd
class Solution:
    def countDifferentSubsequenceGCDs(self, nums):
        present = set(nums)
        mx = max(nums)
        count = 0
        for g in range(1, mx + 1):
            cur = 0
            m = g
            while m <= mx:
                if m in present:
                    cur = gcd(cur, m)
                    if cur == g:
                        break
                m += g
            if cur == g:
                count += 1
        return count

