var countDifferentSubsequenceGCDs = function(nums) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const present = new Set(nums);
    const mx = Math.max(...nums);
    let count = 0;
    for (let g = 1; g <= mx; g++) {
        let cur = 0;
        for (let m = g; m <= mx; m += g) {
            if (present.has(m)) {
                cur = gcd(cur, m);
                if (cur === g) break;
            }
        }
        if (cur === g) count++;
    }
    return count;
};
